# Blocks Cursor Grep/Glob for indexed C# exploration in Elay Backend.
# Forces agent to use codebase-memory MCP instead.
# Allowed: non-indexed file types (.razor, .json, .md, .css, config).

$ErrorActionPreference = 'SilentlyContinue'

$allowedSuffixes = @(
    '.razor', '.json', '.css', '.md', '.markdown',
    '.yml', '.yaml', '.txt', '.config', '.props', '.targets',
    '.http', '.xml', '.gitignore', '.csproj', '.sln', '.editorconfig'
)

function Test-AllowedTarget([string]$value) {
    if ([string]::IsNullOrWhiteSpace($value)) { return $false }
    $lower = $value.ToLowerInvariant()
    foreach ($suffix in $allowedSuffixes) {
        if ($lower.EndsWith($suffix)) { return $true }
    }
    return $false
}

function Test-AllowedGlobPattern([string]$pattern) {
    if ([string]::IsNullOrWhiteSpace($pattern)) { return $false }
    $lower = $pattern.ToLowerInvariant()
    foreach ($suffix in $allowedSuffixes) {
        $bare = $suffix.TrimStart('.')
        if ($lower -like "*$bare*") { return $true }
    }
    return $false
}

$denyMessage = @'
GREP/GLOB BLOCKED by Elay project hook.

For C# code you MUST use codebase-memory MCP (CallMcpTool):
  1. search_graph — classes, handlers, endpoints (name_pattern / semantic_query)
  2. search_code — string literals, error messages
  3. get_code_snippet — read symbol body
  4. trace_path — callers and callees

Grep/Glob is only allowed for: .razor, .json, .css, .md, .yaml, .config, .csproj, .sln

If MCP returns empty: call index_status, ask user to re-index, then retry MCP — do NOT grep .cs files.
'@

$inputText = [Console]::In.ReadToEnd()
if ([string]::IsNullOrWhiteSpace($inputText)) {
    Write-Output '{}'
    exit 0
}

try {
    $payload = $inputText | ConvertFrom-Json
} catch {
    Write-Output '{}'
    exit 0
}

$toolName = $payload.tool_name
$toolInput = $payload.tool_input

if ($toolName -eq 'Grep') {
    $glob = [string]$toolInput.glob
    $path = [string]$toolInput.path

    if ((Test-AllowedTarget $glob) -or (Test-AllowedTarget $path)) {
        Write-Output '{}'
        exit 0
    }

    @{
        permission     = 'deny'
        user_message   = 'Grep blocked — use codebase-memory MCP (search_graph / search_code)'
        agent_message  = $denyMessage
    } | ConvertTo-Json -Compress
    exit 0
}

if ($toolName -eq 'Glob') {
    $pattern = [string]$toolInput.glob_pattern

    if (Test-AllowedGlobPattern $pattern) {
        Write-Output '{}'
        exit 0
    }

    @{
        permission     = 'deny'
        user_message   = 'Glob blocked — use codebase-memory MCP search_graph with file_pattern'
        agent_message  = $denyMessage
    } | ConvertTo-Json -Compress
    exit 0
}

Write-Output '{}'
exit 0

# Global Cursor hook — blocks Grep/Glob for source-code exploration.
# Forces codebase-memory MCP. Allows config/markup/asset file types only.

$ErrorActionPreference = 'SilentlyContinue'

$allowedSuffixes = @(
    '.razor', '.json', '.css', '.scss', '.sass', '.less',
    '.md', '.markdown', '.mdx', '.mdc',
    '.yml', '.yaml', '.toml',
    '.txt', '.config', '.props', '.targets', '.editorconfig',
    '.http', '.xml', '.gitignore', '.dockerignore',
    '.csproj', '.sln', '.fsproj', '.vbproj',
    '.html', '.htm', '.svg', '.ico', '.env', '.env.example',
    '.lock', '.npmrc', '.nvmrc', '.prettierrc'
)

function Test-AllowedTarget([string]$value) {
    if ([string]::IsNullOrWhiteSpace($value)) { return $false }
    $lower = $value.ToLowerInvariant()
    foreach ($suffix in $allowedSuffixes) {
        if ($lower.EndsWith($suffix)) { return $true }
    }
    if ($lower -match '(^|[\\/])(readme|license|changelog)(\.|$)') { return $true }
    return $false
}

function Test-AllowedGlobPattern([string]$pattern) {
    if ([string]::IsNullOrWhiteSpace($pattern)) { return $false }
    $lower = $pattern.ToLowerInvariant()
    foreach ($suffix in $allowedSuffixes) {
        $bare = $suffix.TrimStart('.')
        if ($lower -like "*$bare*") { return $true }
    }
    if ($lower -like '*readme*' -or $lower -like '*license*') { return $true }
    return $false
}

$denyMessage = @'
GREP/GLOB BLOCKED by global Cursor hook.

Use codebase-memory MCP (server: codebase-memory-mcp / user-codebase-memory-mcp):
  1. index_status → index_repository (if project not indexed)
  2. search_graph — symbols (name_pattern / semantic_query / query)
  3. search_code — string literals, error messages
  4. get_code_snippet — read symbol body
  5. trace_path — callers and callees

Grep/Glob allowed ONLY for: .json, .md, .css, .yaml, .config, .html, .csproj, etc.

If MCP empty: re-index with index_repository (mode=full, persistence=true), then retry MCP.
If user explicitly asked for raw grep: state that in reply and ask them to confirm.
'@

$inputText = [Console]::In.ReadToEnd()
if ([string]::IsNullOrWhiteSpace($inputText)) {
    Write-Output '{}'
    exit 0
}

try {
    $payload = $inputText | ConvertFrom-Json
} catch {
    Write-Output '{}'
    exit 0
}

$toolName = $payload.tool_name
$toolInput = $payload.tool_input

if ($toolName -eq 'Grep') {
    $glob = [string]$toolInput.glob
    $path = [string]$toolInput.path

    if ((Test-AllowedTarget $glob) -or (Test-AllowedTarget $path)) {
        Write-Output '{}'
        exit 0
    }

    @{
        permission    = 'deny'
        user_message  = 'Grep blocked globally — use codebase-memory MCP'
        agent_message = $denyMessage
    } | ConvertTo-Json -Compress
    exit 0
}

if ($toolName -eq 'Glob') {
    $pattern = [string]$toolInput.glob_pattern

    if (Test-AllowedGlobPattern $pattern) {
        Write-Output '{}'
        exit 0
    }

    @{
        permission    = 'deny'
        user_message  = 'Glob blocked globally — use codebase-memory MCP search_graph'
        agent_message = $denyMessage
    } | ConvertTo-Json -Compress
    exit 0
}

Write-Output '{}'
exit 0

# Applies Cursor RTL extension patch to main.js (motcke.cursor-rtl)
# Safe to re-run — skips if already patched.

$ErrorActionPreference = 'Stop'

$PatchLine = 'import{createRequire}from"module";try{createRequire(import.meta.url)("./cursor-rtl-loader.cjs")}catch(e){console.error("[Cursor RTL] error loading ./cursor-rtl-loader.cjs: ", e)}'
$OutDir = Join-Path $env:LOCALAPPDATA 'Programs\cursor\resources\app\out'
$MainJsPath = Join-Path $OutDir 'main.js'
$ExtPath = Join-Path $env:USERPROFILE '.cursor\extensions\motcke.cursor-rtl-1.1.8'
$LoaderSrc = Join-Path $ExtPath 'resources\cursor-rtl-loader.cjs'
$LoaderDest = Join-Path $OutDir 'cursor-rtl-loader.cjs'

function Get-Timestamp {
    $now = Get-Date
    return $now.ToString('yyyyMMddTHHmmss')
}

if (-not (Test-Path -LiteralPath $MainJsPath)) {
    Write-Error "main.js not found: $MainJsPath"
}

if (-not (Test-Path -LiteralPath $LoaderSrc)) {
    Write-Error "RTL extension loader missing: $LoaderSrc"
}

Copy-Item -LiteralPath $LoaderSrc -Destination $LoaderDest -Force
Write-Host "LOADER: $LoaderDest"

$content = Get-Content -LiteralPath $MainJsPath -Raw -Encoding UTF8

if ($content -notmatch 'Copyright \(C\) Microsoft Corporation') {
    Write-Error 'main.js signature not found — unsupported Cursor version?'
}

if ($content -like "*cursor-rtl-loader.cjs*") {
    Write-Host 'PATCH: already applied'
    exit 0
}

$backupPath = Join-Path $OutDir ("main.js.rtl-backup-" + (Get-Timestamp))
Copy-Item -LiteralPath $MainJsPath -Destination $backupPath -Force
Write-Host "BACKUP: $backupPath"

$lines = $content -split "`n"
$existingIndex = -1
for ($i = 0; $i -lt $lines.Count; $i++) {
    if ($lines[$i].StartsWith('import{createRequire')) {
        $existingIndex = $i
        break
    }
}

if ($existingIndex -ge 0) {
    $lines[$existingIndex] = $PatchLine
    $patched = ($lines -join "`n")
} else {
    $copyrightEnd = $content.IndexOf('*/')
    if ($copyrightEnd -lt 0) { Write-Error 'copyright block not found in main.js' }
    $insertPos = $copyrightEnd + 2
    $patched = $content.Substring(0, $insertPos) + "`n" + $PatchLine + $content.Substring($insertPos)
}

Set-Content -LiteralPath $MainJsPath -Value $patched -Encoding UTF8 -NoNewline
Write-Host 'PATCH: applied — restart Cursor completely (close all windows)'

# beforeSubmitPrompt — when user writes Persian, remind agent (via block message if needed).
# Normally allows submit; adds no user-visible block.

$ErrorActionPreference = 'SilentlyContinue'

function Test-HasRtlScript([string]$text) {
    if ([string]::IsNullOrWhiteSpace($text)) { return $false }
    foreach ($ch in $text.ToCharArray()) {
        $code = [int][char]$ch
        # Arabic, Persian, Hebrew blocks
        if (($code -ge 0x0600 -and $code -le 0x06FF) -or
            ($code -ge 0x0750 -and $code -le 0x077F) -or
            ($code -ge 0xFB50 -and $code -le 0xFDFF) -or
            ($code -ge 0xFE70 -and $code -le 0xFEFF) -or
            ($code -ge 0x0590 -and $code -le 0x05FF)) {
            return $true
        }
    }
    return $false
}

$inputText = [Console]::In.ReadToEnd()
if ([string]::IsNullOrWhiteSpace($inputText)) {
    Write-Output '{"continue": true}'
    exit 0
}

try {
    $payload = $inputText | ConvertFrom-Json
} catch {
    Write-Output '{"continue": true}'
    exit 0
}

$prompt = [string]$payload.prompt
# Always allow — sessionStart + user rules handle RTL. Hook reserved for future strict mode.
if (Test-HasRtlScript $prompt) {
    Write-Output '{"continue": true}'
    exit 0
}

Write-Output '{"continue": true}'
exit 0

